from __future__ import annotations

from dataclasses import asdict, dataclass, field, is_dataclass
import hashlib
import json
from typing import Any, Dict, List, Mapping, Optional

from src.trader.execution.allocation_candidate import (
    AllocationCandidate,
    normalize_allocation_candidate,
)

VALID_DECISION_STATUS_VALUES = {"APPROVED", "BLOCKED"}


class AllocationDecisionError(RuntimeError):
    """Raised when allocation decision inputs are invalid."""


def _require_non_empty_string(name: str, value: Any) -> str:
    if not isinstance(value, str) or not value.strip():
        raise AllocationDecisionError(f"{name} must be a non-empty string")
    return value.strip()


def _normalize_non_negative_int(name: str, value: Any) -> int:
    if isinstance(value, bool) or not isinstance(value, int):
        raise AllocationDecisionError(f"{name} must be a non-negative integer")
    if value < 0:
        raise AllocationDecisionError(f"{name} must be a non-negative integer")
    return value


def _normalize_non_negative_float(name: str, value: Any) -> float:
    if isinstance(value, bool):
        raise AllocationDecisionError(f"{name} must be a non-negative number")
    if isinstance(value, str):
        try:
            value = float(value.strip())
        except ValueError as exc:
            raise AllocationDecisionError(f"{name} must be a non-negative number") from exc
    if not isinstance(value, (int, float)):
        raise AllocationDecisionError(f"{name} must be a non-negative number")
    normalized = float(value)
    if normalized < 0.0:
        raise AllocationDecisionError(f"{name} must be a non-negative number")
    return normalized


def _normalize_positive_float(name: str, value: Any) -> float:
    normalized = _normalize_non_negative_float(name, value)
    if normalized <= 0.0:
        raise AllocationDecisionError(f"{name} must be a positive number")
    return normalized


def _normalize_metadata(value: Any) -> Dict[str, Any]:
    if value is None:
        return {}
    if not isinstance(value, Mapping):
        raise AllocationDecisionError("metadata must be a mapping when provided")
    return dict(value)


def _normalize_string_list(name: str, value: Any) -> List[str]:
    if value is None:
        return []
    if not isinstance(value, list):
        raise AllocationDecisionError(f"{name} must be a list when provided")
    normalized: List[str] = []
    for item in value:
        normalized.append(_require_non_empty_string(f"{name}[]", item))
    return normalized


def _mapping_from_value(name: str, value: Any) -> Dict[str, Any]:
    if value is None:
        raise AllocationDecisionError(f"{name} is required")

    if isinstance(value, Mapping):
        return dict(value)

    to_dict = getattr(value, "to_dict", None)
    if callable(to_dict):
        payload = to_dict()
        if not isinstance(payload, Mapping):
            raise AllocationDecisionError(f"{name}.to_dict() must return a mapping")
        return dict(payload)

    if is_dataclass(value) and not isinstance(value, type):
        payload = asdict(value)
        if not isinstance(payload, dict):
            raise AllocationDecisionError(f"{name} dataclass did not normalize to a dict")
        return payload

    if hasattr(value, "__dict__"):
        return {key: item for key, item in vars(value).items() if not key.startswith("_")}

    raise AllocationDecisionError(f"{name} must be mapping-like or expose to_dict()")


def _stable_id(prefix: str, payload: Mapping[str, Any]) -> str:
    digest = hashlib.sha256(
        json.dumps(dict(payload), sort_keys=True, default=str).encode("utf-8")
    ).hexdigest()[:16]
    return f"{prefix}_{digest}"


@dataclass(frozen=True)
class AllocationDecisionPolicyReference:
    chain_strategy_budget_policy_id: Optional[str] = None
    budget_candidate_key: Optional[str] = None
    metadata: Dict[str, Any] = field(default_factory=dict)
    allocation_decision_policy_reference_id: str = field(init=False)

    def __post_init__(self) -> None:
        chain_strategy_budget_policy_id = (
            _require_non_empty_string(
                "chain_strategy_budget_policy_id",
                self.chain_strategy_budget_policy_id,
            )
            if self.chain_strategy_budget_policy_id is not None
            else None
        )
        budget_candidate_key = (
            _require_non_empty_string("budget_candidate_key", self.budget_candidate_key)
            if self.budget_candidate_key is not None
            else None
        )
        metadata = _normalize_metadata(self.metadata)

        if chain_strategy_budget_policy_id is None and budget_candidate_key is None:
            raise AllocationDecisionError(
                "AllocationDecisionPolicyReference requires at least one policy reference identifier"
            )

        object.__setattr__(self, "chain_strategy_budget_policy_id", chain_strategy_budget_policy_id)
        object.__setattr__(self, "budget_candidate_key", budget_candidate_key)
        object.__setattr__(self, "metadata", metadata)
        object.__setattr__(
            self,
            "allocation_decision_policy_reference_id",
            _stable_id(
                "allocation_decision_policy_reference",
                {
                    "chain_strategy_budget_policy_id": chain_strategy_budget_policy_id,
                    "budget_candidate_key": budget_candidate_key,
                },
            ),
        )

    def to_dict(self) -> Dict[str, Any]:
        payload = asdict(self)
        payload["metadata"] = dict(self.metadata)
        return payload

    @classmethod
    def from_dict(cls, payload: Mapping[str, Any]) -> "AllocationDecisionPolicyReference":
        if not isinstance(payload, Mapping):
            raise AllocationDecisionError("payload must be a mapping")
        return cls(
            chain_strategy_budget_policy_id=payload.get("chain_strategy_budget_policy_id"),
            budget_candidate_key=payload.get("budget_candidate_key"),
            metadata=dict(payload.get("metadata") or {}),
        )


@dataclass(frozen=True)
class AllocationDecisionItem:
    allocation_candidate_id: str
    chain: str
    strategy_id: str
    symbol: str
    pair: str
    side: str
    proposed_exposure_usd: float
    proposed_position_delta: int
    decision_status: str
    reserved_capital_usd: float = 0.0
    approval_reasons: List[str] = field(default_factory=list)
    block_reasons: List[str] = field(default_factory=list)
    policy_reference: AllocationDecisionPolicyReference | Mapping[str, Any] = field(
        default_factory=lambda: {"budget_candidate_key": "__invalid__"}
    )
    metadata: Dict[str, Any] = field(default_factory=dict)
    allocation_decision_item_id: str = field(init=False)

    def __post_init__(self) -> None:
        allocation_candidate_id = _require_non_empty_string(
            "allocation_candidate_id",
            self.allocation_candidate_id,
        )
        chain = _require_non_empty_string("chain", self.chain).lower()
        strategy_id = _require_non_empty_string("strategy_id", self.strategy_id).lower()
        symbol = _require_non_empty_string("symbol", self.symbol).upper()
        pair = _require_non_empty_string("pair", self.pair).upper()
        side = _require_non_empty_string("side", self.side).upper()
        proposed_exposure_usd = _normalize_positive_float(
            "proposed_exposure_usd",
            self.proposed_exposure_usd,
        )
        proposed_position_delta = _normalize_non_negative_int(
            "proposed_position_delta",
            self.proposed_position_delta,
        )
        decision_status = _require_non_empty_string("decision_status", self.decision_status).upper()
        if decision_status not in VALID_DECISION_STATUS_VALUES:
            raise AllocationDecisionError(
                f"decision_status must be one of {sorted(VALID_DECISION_STATUS_VALUES)}"
            )

        reserved_capital_usd = _normalize_non_negative_float(
            "reserved_capital_usd",
            self.reserved_capital_usd,
        )
        approval_reasons = _normalize_string_list("approval_reasons", self.approval_reasons)
        block_reasons = _normalize_string_list("block_reasons", self.block_reasons)
        policy_reference = (
            self.policy_reference
            if isinstance(self.policy_reference, AllocationDecisionPolicyReference)
            else AllocationDecisionPolicyReference.from_dict(
                _mapping_from_value("policy_reference", self.policy_reference)
            )
        )
        metadata = _normalize_metadata(self.metadata)

        if decision_status == "APPROVED":
            if reserved_capital_usd <= 0.0:
                raise AllocationDecisionError(
                    "approved decisions must reserve positive capital"
                )
            if block_reasons:
                raise AllocationDecisionError(
                    "approved decisions must not include block_reasons"
                )
            if not approval_reasons:
                raise AllocationDecisionError(
                    "approved decisions must include at least one approval reason"
                )

        if decision_status == "BLOCKED":
            if reserved_capital_usd != 0.0:
                raise AllocationDecisionError(
                    "blocked decisions must not reserve capital"
                )
            if not block_reasons:
                raise AllocationDecisionError(
                    "blocked decisions must include at least one block reason"
                )

        object.__setattr__(self, "allocation_candidate_id", allocation_candidate_id)
        object.__setattr__(self, "chain", chain)
        object.__setattr__(self, "strategy_id", strategy_id)
        object.__setattr__(self, "symbol", symbol)
        object.__setattr__(self, "pair", pair)
        object.__setattr__(self, "side", side)
        object.__setattr__(self, "proposed_exposure_usd", proposed_exposure_usd)
        object.__setattr__(self, "proposed_position_delta", proposed_position_delta)
        object.__setattr__(self, "decision_status", decision_status)
        object.__setattr__(self, "reserved_capital_usd", reserved_capital_usd)
        object.__setattr__(self, "approval_reasons", approval_reasons)
        object.__setattr__(self, "block_reasons", block_reasons)
        object.__setattr__(self, "policy_reference", policy_reference)
        object.__setattr__(self, "metadata", metadata)
        object.__setattr__(
            self,
            "allocation_decision_item_id",
            _stable_id(
                "allocation_decision_item",
                {
                    "allocation_candidate_id": allocation_candidate_id,
                    "decision_status": decision_status,
                    "reserved_capital_usd": reserved_capital_usd,
                    "policy_reference_id": policy_reference.allocation_decision_policy_reference_id,
                },
            ),
        )

    def to_dict(self) -> Dict[str, Any]:
        return {
            "allocation_candidate_id": self.allocation_candidate_id,
            "chain": self.chain,
            "strategy_id": self.strategy_id,
            "symbol": self.symbol,
            "pair": self.pair,
            "side": self.side,
            "proposed_exposure_usd": self.proposed_exposure_usd,
            "proposed_position_delta": self.proposed_position_delta,
            "decision_status": self.decision_status,
            "reserved_capital_usd": self.reserved_capital_usd,
            "approval_reasons": list(self.approval_reasons),
            "block_reasons": list(self.block_reasons),
            "policy_reference": self.policy_reference.to_dict(),
            "metadata": dict(self.metadata),
            "allocation_decision_item_id": self.allocation_decision_item_id,
        }

    @classmethod
    def from_dict(cls, payload: Mapping[str, Any]) -> "AllocationDecisionItem":
        if not isinstance(payload, Mapping):
            raise AllocationDecisionError("payload must be a mapping")
        return cls(
            allocation_candidate_id=payload.get("allocation_candidate_id"),
            chain=payload.get("chain"),
            strategy_id=payload.get("strategy_id"),
            symbol=payload.get("symbol"),
            pair=payload.get("pair"),
            side=payload.get("side"),
            proposed_exposure_usd=payload.get("proposed_exposure_usd"),
            proposed_position_delta=payload.get("proposed_position_delta", 0),
            decision_status=payload.get("decision_status"),
            reserved_capital_usd=payload.get("reserved_capital_usd", 0.0),
            approval_reasons=list(payload.get("approval_reasons") or []),
            block_reasons=list(payload.get("block_reasons") or []),
            policy_reference=payload.get("policy_reference"),
            metadata=dict(payload.get("metadata") or {}),
        )


@dataclass(frozen=True)
class AllocationDecision:
    allocator_cycle_id: str
    approved_items: List[AllocationDecisionItem] = field(default_factory=list)
    blocked_items: List[AllocationDecisionItem] = field(default_factory=list)
    metadata: Dict[str, Any] = field(default_factory=dict)
    allocation_decision_id: str = field(init=False)
    total_reserved_capital_usd: float = field(init=False)
    approved_candidate_ids: List[str] = field(init=False)
    blocked_candidate_ids: List[str] = field(init=False)

    def __post_init__(self) -> None:
        allocator_cycle_id = _require_non_empty_string("allocator_cycle_id", self.allocator_cycle_id)
        approved_items = [
            item if isinstance(item, AllocationDecisionItem) else AllocationDecisionItem.from_dict(_mapping_from_value("approved_item", item))
            for item in self.approved_items
        ]
        blocked_items = [
            item if isinstance(item, AllocationDecisionItem) else AllocationDecisionItem.from_dict(_mapping_from_value("blocked_item", item))
            for item in self.blocked_items
        ]
        metadata = _normalize_metadata(self.metadata)

        if not approved_items and not blocked_items:
            raise AllocationDecisionError(
                "AllocationDecision must include at least one approved or blocked item"
            )

        for item in approved_items:
            if item.decision_status != "APPROVED":
                raise AllocationDecisionError("approved_items may contain only APPROVED decision items")
        for item in blocked_items:
            if item.decision_status != "BLOCKED":
                raise AllocationDecisionError("blocked_items may contain only BLOCKED decision items")

        approved_candidate_ids = [item.allocation_candidate_id for item in approved_items]
        blocked_candidate_ids = [item.allocation_candidate_id for item in blocked_items]
        duplicate_candidate_ids = set(approved_candidate_ids).intersection(blocked_candidate_ids)
        if duplicate_candidate_ids:
            raise AllocationDecisionError(
                "the same allocation_candidate_id cannot appear in both approved_items and blocked_items"
            )

        total_reserved_capital_usd = round(
            sum(item.reserved_capital_usd for item in approved_items),
            8,
        )

        object.__setattr__(self, "allocator_cycle_id", allocator_cycle_id)
        object.__setattr__(self, "approved_items", approved_items)
        object.__setattr__(self, "blocked_items", blocked_items)
        object.__setattr__(self, "metadata", metadata)
        object.__setattr__(self, "total_reserved_capital_usd", total_reserved_capital_usd)
        object.__setattr__(self, "approved_candidate_ids", approved_candidate_ids)
        object.__setattr__(self, "blocked_candidate_ids", blocked_candidate_ids)
        object.__setattr__(
            self,
            "allocation_decision_id",
            _stable_id(
                "allocation_decision",
                {
                    "allocator_cycle_id": allocator_cycle_id,
                    "approved_item_ids": [item.allocation_decision_item_id for item in approved_items],
                    "blocked_item_ids": [item.allocation_decision_item_id for item in blocked_items],
                    "total_reserved_capital_usd": total_reserved_capital_usd,
                },
            ),
        )

    def to_dict(self) -> Dict[str, Any]:
        return {
            "allocator_cycle_id": self.allocator_cycle_id,
            "approved_items": [item.to_dict() for item in self.approved_items],
            "blocked_items": [item.to_dict() for item in self.blocked_items],
            "metadata": dict(self.metadata),
            "allocation_decision_id": self.allocation_decision_id,
            "total_reserved_capital_usd": self.total_reserved_capital_usd,
            "approved_candidate_ids": list(self.approved_candidate_ids),
            "blocked_candidate_ids": list(self.blocked_candidate_ids),
        }

    @classmethod
    def from_dict(cls, payload: Mapping[str, Any]) -> "AllocationDecision":
        if not isinstance(payload, Mapping):
            raise AllocationDecisionError("payload must be a mapping")
        return cls(
            allocator_cycle_id=payload.get("allocator_cycle_id"),
            approved_items=list(payload.get("approved_items") or []),
            blocked_items=list(payload.get("blocked_items") or []),
            metadata=dict(payload.get("metadata") or {}),
        )


def normalize_allocation_decision_item(item: Any) -> AllocationDecisionItem:
    if isinstance(item, AllocationDecisionItem):
        return item
    payload = _mapping_from_value("decision_item", item)
    return AllocationDecisionItem.from_dict(payload)


def normalize_allocation_decision(decision: Any) -> AllocationDecision:
    if isinstance(decision, AllocationDecision):
        return decision
    payload = _mapping_from_value("decision", decision)
    return AllocationDecision.from_dict(payload)


def allocation_decision_item_from_candidate_and_budget_result(
    *,
    candidate: Any,
    budget_result: Any,
    approval_reasons: Optional[List[str]] = None,
    metadata: Optional[Mapping[str, Any]] = None,
) -> AllocationDecisionItem:
    normalized_candidate = normalize_allocation_candidate(candidate)
    normalized_budget_result = _mapping_from_value("budget_result", budget_result)

    should_allow_allocation = normalized_budget_result.get("should_allow_allocation")
    is_blocked = normalized_budget_result.get("is_blocked")
    if not isinstance(should_allow_allocation, bool) or not isinstance(is_blocked, bool):
        raise AllocationDecisionError(
            "budget_result must include boolean should_allow_allocation and is_blocked fields"
        )
    if should_allow_allocation == is_blocked:
        raise AllocationDecisionError(
            "budget_result should_allow_allocation and is_blocked must be opposite booleans"
        )

    policy_reference = AllocationDecisionPolicyReference(
        chain_strategy_budget_policy_id=normalized_budget_result.get("chain_strategy_budget_policy_id"),
        budget_candidate_key=normalized_budget_result.get("budget_candidate_key"),
        metadata=dict(normalized_budget_result.get("policy_reference_metadata") or {}),
    )

    merged_metadata: Dict[str, Any] = dict(metadata or {})
    merged_metadata["lineage_id"] = normalized_candidate.lineage.allocation_candidate_lineage_id
    merged_metadata["portfolio_context_id"] = normalized_candidate.portfolio_context.allocation_portfolio_context_id

    if should_allow_allocation:
        normalized_approval_reasons = list(approval_reasons or ["budget policy allowed allocation"])
        return AllocationDecisionItem(
            allocation_candidate_id=normalized_candidate.allocation_candidate_id,
            chain=normalized_candidate.chain,
            strategy_id=normalized_candidate.strategy_id,
            symbol=normalized_candidate.symbol,
            pair=normalized_candidate.pair,
            side=normalized_candidate.side,
            proposed_exposure_usd=normalized_candidate.proposed_exposure_usd,
            proposed_position_delta=normalized_candidate.proposed_position_delta,
            decision_status="APPROVED",
            reserved_capital_usd=normalized_candidate.proposed_exposure_usd,
            approval_reasons=normalized_approval_reasons,
            block_reasons=[],
            policy_reference=policy_reference,
            metadata=merged_metadata,
        )

    block_reasons = list(normalized_budget_result.get("block_reasons") or [])
    return AllocationDecisionItem(
        allocation_candidate_id=normalized_candidate.allocation_candidate_id,
        chain=normalized_candidate.chain,
        strategy_id=normalized_candidate.strategy_id,
        symbol=normalized_candidate.symbol,
        pair=normalized_candidate.pair,
        side=normalized_candidate.side,
        proposed_exposure_usd=normalized_candidate.proposed_exposure_usd,
        proposed_position_delta=normalized_candidate.proposed_position_delta,
        decision_status="BLOCKED",
        reserved_capital_usd=0.0,
        approval_reasons=[],
        block_reasons=block_reasons,
        policy_reference=policy_reference,
        metadata=merged_metadata,
    )


def build_allocation_decision(
    *,
    allocator_cycle_id: Any,
    decision_items: List[Any],
    metadata: Optional[Mapping[str, Any]] = None,
) -> AllocationDecision:
    normalized_items = [
        normalize_allocation_decision_item(item)
        for item in decision_items
    ]
    approved_items = [item for item in normalized_items if item.decision_status == "APPROVED"]
    blocked_items = [item for item in normalized_items if item.decision_status == "BLOCKED"]
    return AllocationDecision(
        allocator_cycle_id=allocator_cycle_id,
        approved_items=approved_items,
        blocked_items=blocked_items,
        metadata=dict(metadata or {}),
    )
